-- Verificar jogadores inseridos com ligas que podem ser problemáticas
SELECT name, club, league, overall FROM players 
WHERE league IN ('Ukrainian Premier League', 'Saudi Pro League', 'Liga Profesional', 'Brasileirão', 'Bundesliga Austria', 'Allsvenskan', 'Serie B', 'Championship', 'Süper Lig')
ORDER BY league, overall DESC;

